from typing import Any

class HashTable:
    def __init__(self, m: int = 16):
        self.m = m
        self.buckets: list[list[tuple[Any, Any]]] = [[] for _ in range(m)]

    def _slot(self, key) -> int:
        return hash(key) % self.m

    def put(self, key, value):
        bucket = self.buckets[self._slot(key)]
        for i, (k, _) in enumerate(bucket):
            if k == key:
                bucket[i] = (key, value)
                return
        bucket.append((key, value))

    def get(self, key, default=None):
        for k, v in self.buckets[self._slot(key)]:
            if k == key:
                return v
        return default

ht = HashTable()
ht.put("alice", 30); ht.put("bob", 22)
print(ht.get("alice"))   # 30

